contracts/oracle/OracleManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

import "../structs/DataTypes.sol";
import "../libraries/Errors.sol";

contract OracleManager is AccessControl {

    bytes32 public constant ORACLE_ROLE =
        keccak256("ORACLE_ROLE");

    mapping(
        uint256 =>
        DataTypes.DeliveryStatus
    ) internal deliveryStatus;

    event OracleAdded(
        address indexed oracle
    );

    event OracleRemoved(
        address indexed oracle
    );

    event DeliveryConfirmed(
        uint256 indexed tradeId,
        bool success
    );

    event FraudReported(
        uint256 indexed tradeId
    );

    constructor(address admin) {
        _grantRole(
            DEFAULT_ADMIN_ROLE,
            admin
        );
    }

    function addOracle(
        address oracle
    )
        external
        onlyRole(
            DEFAULT_ADMIN_ROLE
        )
    {
        _grantRole(
            ORACLE_ROLE,
            oracle
        );

        emit OracleAdded(
            oracle
        );
    }

    function removeOracle(
        address oracle
    )
        external
        onlyRole(
            DEFAULT_ADMIN_ROLE
        )
    {
        _revokeRole(
            ORACLE_ROLE,
            oracle
        );

        emit OracleRemoved(
            oracle
        );
    }

    function confirmDelivery(
        uint256 tradeId,
        bool success
    )
        external
        onlyRole(
            ORACLE_ROLE
        )
    {
        if (
            deliveryStatus[
                tradeId
            ] !=
            DataTypes
                .DeliveryStatus
                .PENDING
        ) {
            revert Errors
                .InvalidState();
        }

        if (success) {
            deliveryStatus[
                tradeId
            ] =
                DataTypes
                .DeliveryStatus
                .SUCCESS;
        } else {
            deliveryStatus[
                tradeId
            ] =
                DataTypes
                .DeliveryStatus
                .FAILED;
        }

        emit DeliveryConfirmed(
            tradeId,
            success
        );
    }

    function reportFraud(
        uint256 tradeId
    )
        external
        onlyRole(
            ORACLE_ROLE
        )
    {
        deliveryStatus[
            tradeId
        ] =
            DataTypes
            .DeliveryStatus
            .FRAUD;

        emit FraudReported(
            tradeId
        );
    }

    function getDeliveryStatus(
        uint256 tradeId
    )
        external
        view
        returns (
            DataTypes
                .DeliveryStatus
        )
    {
        return deliveryStatus[
            tradeId
        ];
    }

    function isOracle(
        address oracle
    )
        external
        view
        returns (bool)
    {
        return hasRole(
            ORACLE_ROLE,
            oracle
        );
    }
}

