contracts/structs/DataTypes.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

library DataTypes {

    // User types
    struct User {
        address wallet;
        uint256 reputation;
        uint256 reputationLastUpdated;
        uint256 registeredAt;
        bool active;
    }

    // Trade types
    enum TradeStatus {
        CREATED,
        ACTIVE,
        COMPLETED,
        CANCELLED,
        EXPIRED
    }

    struct Trade {
        uint256 id;
        uint256 engineTradeId;

        address seller;
        address buyer;

        uint256 energyAmount;
        uint256 tradePrice;

        bool sellerConfirmed;
        bool buyerConfirmed;

        uint256 createdAt;
        uint256 expiryTime;

        TradeStatus status;
    }

    // Escrow types
    struct Escrow {
        uint256 buyerDeposit;
        uint256 buyerStake;
        uint256 sellerStake;

        bool buyerFunded;
        bool sellerFunded;

        bool settled;
    }

    // Oracle/Delivery types
    enum DeliveryStatus {
        PENDING,
        SUCCESS,
        FAILED,
        FRAUD
    }
}

