// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "../structs/DataTypes.sol";

abstract contract AppStorage {

    mapping(address => DataTypes.User)
        internal users;

    mapping(uint256 => DataTypes.Trade)
        internal trades;

    mapping(uint256 => DataTypes.Escrow)
        internal escrows;

    mapping(
        uint256 =>
        DataTypes.DeliveryStatus
    ) internal deliveryStatus;

    uint256 internal nextTradeId;
}

