import "@openzeppelin/contracts/access/AccessControl.sol";

abstract contract ModuleAccess is AccessControl {

    bytes32 public constant
        MATCHING_ENGINE_ROLE =
        keccak256(
            "MATCHING_ENGINE_ROLE"
        );

    bytes32 public constant
        ORACLE_ENGINE_ROLE =
        keccak256(
            "ORACLE_ENGINE_ROLE"
        );

    constructor(address admin) {
        _grantRole(
            DEFAULT_ADMIN_ROLE,
            admin
        );
    }
