contracts/registry/UserRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

import "../structs/DataTypes.sol";
import "../libraries/Errors.sol";

contract UserRegistry is AccessControl {

    // this file should not have access to engine_role
    // it should be given to different file which handles
    // both the python matching engine as well as the
    // oracle engine
    bytes32 public constant ENGINE_ROLE =
        keccak256("ENGINE_ROLE");

    mapping(address => DataTypes.User) internal users;

    event UserRegistered(
        address indexed user,
        uint256 timestamp
    );

    event UserActivated(
        address indexed user
    );

    event UserDeactivated(
        address indexed user
    );

    event ReputationUpdated(
        address indexed user,
        uint256 reputation
    );

    constructor(address admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
    }

    modifier onlyRegisteredUser(address user) {
        if (users[user].wallet == address(0)) {
            revert Errors.UserNotRegistered();
        }
        _;
    }

    function registerUser() external {

        if (users[msg.sender].wallet != address(0)) {
            revert Errors.UserAlreadyRegistered();
        }

        users[msg.sender] = DataTypes.User({
            wallet: msg.sender,
            reputation: 0,
            reputationLastUpdated: 0,
            registeredAt: block.timestamp,
            active: true
        });

        emit UserRegistered(
            msg.sender,
            block.timestamp
        );
    }

    function deactivateUser(
        address user
    )
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
        onlyRegisteredUser(user)
    {
        if (!users[user].active) {
            revert Errors.UserAlreadyInactive();
        }

        users[user].active = false;

        emit UserDeactivated(user);
    }

    function activateUser(
        address user
    )
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
        onlyRegisteredUser(user)
    {
        if (users[user].active) {
            revert Errors.UserAlreadyActive();
        }

        users[user].active = true;

        emit UserActivated(user);
    }

    function updateReputation(
        address user,
        uint256 reputation
    )
        external
        onlyRole(ENGINE_ROLE)
        onlyRegisteredUser(user)
    {
        users[user].reputation = reputation;
        users[user].reputationLastUpdated = block.timestamp;

        emit ReputationUpdated(
            user,
            reputation
        );
    }

    function getUser(
        address user
    )
        external
        view
        onlyRegisteredUser(user)
        returns (DataTypes.User memory)
    {
        return users[user];
    }

    function isRegistered(
        address user
    )
        public
        view
        returns (bool)
    {
        return users[user].wallet != address(0);
    }

    function isActive(
        address user
    )
        public
        view
        returns (bool)
    {
        return users[user].active;
    }

    function getReputation(
        address user
    )
        public
        view
        returns (uint256)
    {
        return users[user].reputation;
    }

    // TODO: addEngine and removeEngine should be in different files

    function addEngine(
        address engine
    )
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        _grantRole(
            ENGINE_ROLE,
            engine
        );
    }

    function removeEngine(
        address engine
    )
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        _revokeRole(
            ENGINE_ROLE,
            engine
        );
    }
}

