contracts/trade/TradeManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

import "../structs/DataTypes.sol";
import "../libraries/Errors.sol";
import "../libraries/Roles.sol";

contract TradeManager is AccessControl {

    uint256 public nextTradeId;

    mapping(
        uint256 =>
        DataTypes.Trade
    ) internal trades;

    event TradeCreated(
        uint256 indexed tradeId,
        uint256 indexed engineTradeId,
        address indexed seller,
        address buyer
    );

    event TradeConfirmed(
        uint256 indexed tradeId,
        address indexed user
    );

    event TradeActivated(
        uint256 indexed tradeId
    );

    event TradeExpired(
        uint256 indexed tradeId
    );

    constructor(address admin) {
        _grantRole(
            DEFAULT_ADMIN_ROLE,
            admin
        );
    }

    // all of these functions could be accessed by the
    // python engine only
    function createTrade(
        uint256 engineTradeId,
        address seller,
        address buyer,
        uint256 energyAmount,
        uint256 tradePrice,
        uint256 expiryTime
    )
        external
        onlyRole(
            Roles.ENGINE_ROLE
        )
    {
        if (
            seller == address(0) ||
            buyer == address(0)
        ) {
            revert Errors
                .InvalidUser();
        }

        if (
            seller == buyer
        ) {
            revert Errors
                .InvalidUser();
        }

        uint256 tradeId =
            nextTradeId++;

        trades[tradeId] =
            DataTypes.Trade({
                id: tradeId,
                engineTradeId:
                    engineTradeId,
                seller: seller,
                buyer: buyer,
                energyAmount:
                    energyAmount,
                tradePrice:
                    tradePrice,
                sellerConfirmed:
                    false,
                buyerConfirmed:
                    false,
                createdAt:
                    block.timestamp,
                expiryTime:
                    expiryTime,
                status:
                    DataTypes
                    .TradeStatus
                    .CREATED
            });

        emit TradeCreated(
            tradeId,
            engineTradeId,
            seller,
            buyer
        );
    }

    function confirmTrade(uint256 tradeId)
        external
    {
        DataTypes.Trade
            storage trade =
            trades[tradeId];

        if (
            trade.status !=
            DataTypes
                .TradeStatus
                .CREATED
        ) {
            revert Errors
                .InvalidState();
        }

        if (
            block.timestamp >
            trade.expiryTime
        ) {
            revert Errors
                .TradeExpiredError();
        }

        if (
            msg.sender !=
            trade.seller &&
            msg.sender !=
            trade.buyer
        ) {
            revert Errors
                .UnauthorizedCaller();
        }

        if (
            msg.sender ==
            trade.seller
        ) {
            trade
                .sellerConfirmed =
                true;
        }

        if (
            msg.sender ==
            trade.buyer
        ) {
            trade
                .buyerConfirmed =
                true;
        }

        emit TradeConfirmed(
            tradeId,
            msg.sender
        );

        if (
            trade
                .sellerConfirmed &&
            trade
                .buyerConfirmed
        ) {
            trade.status =
                DataTypes
                .TradeStatus
                .ACTIVE;

            emit TradeActivated(
                tradeId
            );
        }
    }

    function expireTrade(
        uint256 tradeId
    )
        external
    {
        DataTypes.Trade
            storage trade =
            trades[tradeId];

        if (
            trade.status !=
            DataTypes
                .TradeStatus
                .CREATED
        ) {
            revert Errors
                .InvalidState();
        }

        if (
            block.timestamp <=
            trade.expiryTime
        ) {
            revert Errors
                .InvalidState();
        }

        trade.status =
            DataTypes
                .TradeStatus
                .EXPIRED;

        emit TradeExpired(
            tradeId
        );
    }

    function getTrade(
        uint256 tradeId
    )
        external
        view
        returns (
            DataTypes.Trade memory
        )
    {
        return trades[tradeId];
    }

    // TODO: remove this addEngine and remove Engine and move it to a new place

    function addEngine(
        address engine
    )
        external
        onlyRole(
            DEFAULT_ADMIN_ROLE
        )
    {
        _grantRole(
            Roles.ENGINE_ROLE,
            engine
        );
    }

    function removeEngine(
        address engine
    )
        external
        onlyRole(
            DEFAULT_ADMIN_ROLE
        )
    {
        _revokeRole(
            Roles.ENGINE_ROLE,
            engine
        );
    }
}

