contract/TradeModule.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./UserModule.sol";

abstract contract TradeModule is UserModule {
    enum TradeStatus { IN_PROGRESS, ACTIVE, COMPLETED, CANCELLED, FRAUD_REPORTED }
    enum OracleResult { COMPLETED, FAILURE, FRAUD }

    struct Trade {
        uint256 seller;
        uint256 buyer;
        uint256 energy;
        uint256 price;
        uint256 stake;
        address pythonAddress;
        address oracleAddress;
        TradeStatus status;
        bool moneyCollected;
        uint256 expiryTime;
    }

    event TradeInitiated(uint256 indexed tradeId, address indexed oracleAddress);

    mapping(uint256 => Trade) public trades;

    address public engineOracle;

    event InsufficientFunds(uint256 indexed tradeId, uint256 indexed meterId, string reason);

    function setEngineOracle(address _engineOracle) external onlyOwner {
        engineOracle = _engineOracle;
    }

    function createTrade(
        uint256 tradeId, 
        uint256 _seller, 
        uint256 _buyer, 
        uint256 _energy, 
        uint256 _price,
        uint256 _stake,
        address _pythonAddress, 
        address _oracleAddress
    ) external nonReentrant {
        require(msg.sender == engineOracle, "Only engine oracle can create trades");
        require(trades[tradeId].expiryTime == 0, "Trade already exists");

        trades[tradeId] = Trade({
            seller: _seller,
            buyer: _buyer,
            energy: _energy,
            price: _price,
            stake: _stake,
            pythonAddress: _pythonAddress,
            oracleAddress: _oracleAddress,
            status: TradeStatus.IN_PROGRESS,
            moneyCollected: false,
            expiryTime: block.timestamp + 10 minutes
        });

        if (!_getStakes(tradeId)) {
            trades[tradeId].status = TradeStatus.CANCELLED;
            return;
        }

        if (!_getMoneyFromBuyer(tradeId)) {
            modifyBalance(_buyer, _stake, false);
            modifyBalance(_seller, _stake, false);
            trades[tradeId].status = TradeStatus.CANCELLED;
            return;
        }

        trades[tradeId].status = TradeStatus.ACTIVE;
        emit TradeInitiated(tradeId, _oracleAddress);
    }

    function _getStakes(uint256 tradeId) internal returns (bool) {
        Trade storage currentTrade = trades[tradeId];

        if (users[currentTrade.buyer].amountStored < currentTrade.stake) {
            emit InsufficientFunds(tradeId, currentTrade.buyer, "Buyer insufficient funds for stake");
            return false;
        }
        if (users[currentTrade.seller].amountStored < currentTrade.stake) {
            emit InsufficientFunds(tradeId, currentTrade.seller, "Seller insufficient funds for stake");
            return false;
        }

        modifyBalance(currentTrade.buyer, currentTrade.stake, true);
        modifyBalance(currentTrade.seller, currentTrade.stake, true);
        return true;
    }

    function _getMoneyFromBuyer(uint256 tradeId) internal returns (bool) {
        Trade storage currentTrade = trades[tradeId];

        if (users[currentTrade.buyer].amountStored < currentTrade.price) {
            emit InsufficientFunds(tradeId, currentTrade.buyer, "Buyer insufficient funds for price");
            return false;
        }

        modifyBalance(currentTrade.buyer, currentTrade.price, true);
        currentTrade.moneyCollected = true;
        return true;
    }

    function checkOracle(uint256 tradeId, OracleResult result) external nonReentrant {
        Trade storage currentTrade = trades[tradeId];
        require(msg.sender == currentTrade.oracleAddress || msg.sender == engineOracle, "Unauthorized");
        require(currentTrade.status == TradeStatus.ACTIVE, "Trade is not active");
        require(block.timestamp <= currentTrade.expiryTime, "Trade has expired");

        if (result == OracleResult.COMPLETED) {
            currentTrade.status = TradeStatus.COMPLETED;
            _settleTradeSuccess(tradeId);
        } else if (result == OracleResult.FAILURE) {
            currentTrade.status = TradeStatus.CANCELLED;
            _refundAll(tradeId);
        } else if (result == OracleResult.FRAUD) {
            currentTrade.status = TradeStatus.FRAUD_REPORTED;
            _penalizeSellerFraud(tradeId);
        }
    }

    function _settleTradeSuccess(uint256 tradeId) internal {
        Trade storage currentTrade = trades[tradeId];

        modifyBalance(currentTrade.seller, currentTrade.price, false);

        modifyBalance(currentTrade.buyer, currentTrade.stake, false);
        modifyBalance(currentTrade.seller, currentTrade.stake, false);
    }

    function _refundAll(uint256 tradeId) internal {
        Trade storage currentTrade = trades[tradeId];

        modifyBalance(currentTrade.buyer, currentTrade.price, false);

        modifyBalance(currentTrade.buyer, currentTrade.stake, false);
        modifyBalance(currentTrade.seller, currentTrade.stake, false);
    }

    function _penalizeSellerFraud(uint256 tradeId) internal {
        Trade storage currentTrade = trades[tradeId];

        modifyBalance(currentTrade.buyer, currentTrade.price, false);

        modifyBalance(currentTrade.buyer, currentTrade.stake, false);

        modifyBalance(currentTrade.buyer, currentTrade.stake, false);
    }
}

contract/UserModule.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

abstract contract UserModule is ReentrancyGuard, Ownable {
    struct User {
        address wallet;
        string username;
        uint256 reputation;
        uint256 amountStored;
    }

    mapping(uint256 => User) public users;

    address public centralContract;

    modifier onlyAuthorized() {
        require(msg.sender == centralContract || msg.sender == owner(), "Not authorized");
        _;
    }

    function setCentralContract(address _centralContract) external onlyOwner {
        centralContract = _centralContract;
    }

    function registerUser(uint256 meterId, string memory _username) external {
        require(users[meterId].wallet == address(0), "Meter ID already registered");

        users[meterId] = User({
            wallet: msg.sender,
            username: _username,
            reputation: 100, 
            amountStored: 0
        });
    }

    function payAmount(uint256 meterId) external payable nonReentrant {
        require(users[meterId].wallet == msg.sender, "Only the registered wallet can pay");
        users[meterId].amountStored += msg.value;
    }

    function updateReputation(uint256 meterId, uint256 newReputation) external onlyAuthorized {
        users[meterId].reputation = newReputation;
    }

    function transferAmount(uint256 meterId, uint256 amount) external nonReentrant {
        require(users[meterId].wallet == msg.sender, "Only the registered wallet can withdraw");
        require(users[meterId].amountStored >= amount, "Insufficient balance");

        users[meterId].amountStored -= amount;
        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");
    }

    function modifyBalance(uint256 meterId, uint256 amount, bool isDeduction) internal {
        if (isDeduction) {
            require(users[meterId].amountStored >= amount, "Insufficient stored amount");
            users[meterId].amountStored -= amount;
        } else {
            users[meterId].amountStored += amount;
        }
    }
}

